    15→import { sendMarkdownCardFeishu, sendMessageFeishu } from "./send.js";
    16→import { FeishuStreamingSession, mergeStreamingText } from "./streaming-card.js";
    17→import { resolveReceiveIdType } from "./targets.js";
    18→import { addTypingIndicator, removeTypingIndicator, type TypingIndicatorState } from "./typing.js";
