    24→
    25→/** Maximum age (ms) for a message to receive a typing indicator reaction.
    26→ * Messages older than this are likely replays after context compaction (#30418). */
    27→const TYPING_INDICATOR_MAX_AGE_MS = 2 * 60_000;
    28→const MS_EPOCH_MIN = 1_000_000_000_000;
    29→
    30→function normalizeEpochMs(timestamp: number | undefined): number | undefined {
    31→  if (!Number.isFinite(timestamp) || timestamp === undefined || timestamp <= 0) {
    32→    return undefined;
    33→  }
    34→  // Defensive normalization: some payloads use seconds, others milliseconds.
    35→  // Values below 1e12 are treated as epoch-seconds.
    36→  return timestamp < MS_EPOCH_MIN ? timestamp * 1000 : timestamp;
    37→}
    38→
    39→export type CreateFeishuReplyDispatcherParams = {
    40→  cfg: ClawdbotConfig;
    41→  agentId: string;
    42→  runtime: RuntimeEnv;
    43→  chatId: string;
    44→  replyToMessageId?: string;
    45→  /** When true, preserve typing indicator on reply target but send messages without reply metadata */
    46→  skipReplyToInMessages?: boolean;
    47→  replyInThread?: boolean;
    48→  /** True when inbound message is already inside a thread/topic context */
    49→  threadReply?: boolean;
    50→  rootId?: string;
    51→  mentionTargets?: MentionTarget[];
    52→  accountId?: string;
    53→  /** Epoch ms when the inbound message was created. Used to suppress typing
    54→   *  indicators on old/replayed messages after context compaction (#30418). */
    55→  messageCreateTimeMs?: number;
    56→};
    57→
    58→export function createFeishuReplyDispatcher(params: CreateFeishuReplyDispatcherParams) {
    59→  const core = getFeishuRuntime();
    60→  const {
    61→    cfg,
    62→    agentId,
    63→    chatId,
    64→    replyToMessageId,
    65→    skipReplyToInMessages,
    66→    replyInThread,
    67→    threadReply,
    68→    rootId,
    69→    mentionTargets,
    70→    accountId,
    71→  } = params;
    72→  const sendReplyToMessageId = skipReplyToInMessages ? undefined : replyToMessageId;
    73→  const threadReplyMode = threadReply === true;
    74→  const effectiveReplyInThread = threadReplyMode ? true : replyInThread;
    75→  const account = resolveFeishuAccount({ cfg, accountId });
    76→  const prefixContext = createReplyPrefixContext({ cfg, agentId });
    77→
    78→  let typingState: TypingIndicatorState | null = null;
    79→  const typingCallbacks = createTypingCallbacks({
    80→    start: async () => {
    81→      // Check if typing indicator is enabled (default: true)
    82→      if (!(account.config.typingIndicator ?? true)) {
    83→        return;
    84→      }
    85→      if (!replyToMessageId) {
    86→        return;
    87→      }
    88→      // Skip typing indicator for old messages — likely replays after context
    89→      // compaction that would flood users with stale notifications (#30418).
    90→      const messageCreateTimeMs = normalizeEpochMs(params.messageCreateTimeMs);
    91→      if (
    92→        messageCreateTimeMs !== undefined &&
    93→        Date.now() - messageCreateTimeMs > TYPING_INDICATOR_MAX_AGE_MS
    94→      ) {
    95→        return;
    96→      }
    97→      // Feishu reactions persist until explicitly removed, so skip keepalive
    98→      // re-adds when a reaction already exists. Re-adding the same emoji
    99→      // triggers a new push notification for every call (#28660).
   100→      if (typingState?.reactionId) {
   101→        return;
   102→      }
   103→      typingState = await addTypingIndicator({
   104→        cfg,
   105→        messageId: replyToMessageId,
   106→        accountId,
   107→        runtime: params.runtime,
   108→      });
   109→    },
   110→    stop: async () => {
   111→      if (!typingState) {
   112→        return;
   113→      }
   114→      await removeTypingIndicator({ cfg, state: typingState, accountId, runtime: params.runtime });
   115→      typingState = null;
   116→    },
   117→    onStartError: (err) =>
   118→      logTypingFailure({
   119→        log: (message) => params.runtime.log?.(message),
   120→        channel: "feishu",
   121→        action: "start",
   122→        error: err,
   123→      }),
   124→    onStopError: (err) =>
   125→      logTypingFailure({
   126→        log: (message) => params.runtime.log?.(message),
   127→        channel: "feishu",
   128→        action: "stop",
   129→        error: err,
   130→      }),
   131→  });
   132→
   133→  const textChunkLimit = core.channel.text.resolveTextChunkLimit(cfg, "feishu", accountId, {
   134→    fallbackLimit: 4000,
   135→  });
   136→  const chunkMode = core.channel.text.resolveChunkMode(cfg, "feishu");
   137→  const tableMode = core.channel.text.resolveMarkdownTableMode({ cfg, channel: "feishu" });
   138→  const renderMode = account.config?.renderMode ?? "auto";
   139→  // Card streaming may miss thread affinity in topic contexts; use direct replies there.
   140→  const streamingEnabled =
   141→    !threadReplyMode && account.config?.streaming !== false && renderMode !== "raw";
   142→
   143→  let streaming: FeishuStreamingSession | null = null;
   144→  let streamText = "";
   145→  let lastPartial = "";
   146→  const deliveredFinalTexts = new Set<string>();
   147→  let partialUpdateQueue: Promise<void> = Promise.resolve();
   148→  let streamingStartPromise: Promise<void> | null = null;
   149→  type StreamTextUpdateMode = "snapshot" | "delta";
   150→
   151→  const queueStreamingUpdate = (
   152→    nextText: string,
   153→    options?: {
   154→      dedupeWithLastPartial?: boolean;
   155→      mode?: StreamTextUpdateMode;
   156→    },
   157→  ) => {
   158→    if (!nextText) {
   159→      return;
   160→    }
   161→    if (options?.dedupeWithLastPartial && nextText === lastPartial) {
   162→      return;
   163→    }
   164→    if (options?.dedupeWithLastPartial) {
   165→      lastPartial = nextText;
   166→    }
   167→    const mode = options?.mode ?? "snapshot";
   168→    streamText =
   169→      mode === "delta" ? `${streamText}${nextText}` : mergeStreamingText(streamText, nextText);
   170→    partialUpdateQueue = partialUpdateQueue.then(async () => {
   171→      if (streamingStartPromise) {
   172→        await streamingStartPromise;
   173→      }
   174→      if (streaming?.isActive()) {
   175→        await streaming.update(streamText);
   176→      }
   177→    });
   178→  };
   179→
   180→  const startStreaming = () => {
   181→    if (!streamingEnabled || streamingStartPromise || streaming) {
   182→      return;
   183→    }
   184→    streamingStartPromise = (async () => {
   185→      const creds =
   186→        account.appId && account.appSecret
   187→          ? { appId: account.appId, appSecret: account.appSecret, domain: account.domain }
   188→          : null;
   189→      if (!creds) {
   190→        return;
   191→      }
   192→
   193→      streaming = new FeishuStreamingSession(createFeishuClient(account), creds, (message) =>
   194→        params.runtime.log?.(`feishu[${account.accountId}] ${message}`),
   195→      );
   196→      try {
   197→        await streaming.start(chatId, resolveReceiveIdType(chatId), {
   198→          replyToMessageId,
   199→          replyInThread: effectiveReplyInThread,
   200→          rootId,
   201→        });
   202→      } catch (error) {
   203→        params.runtime.error?.(`feishu: streaming start failed: ${String(error)}`);
   204→        streaming = null;
   205→      }
   206→    })();
   207→  };
   208→
   209→  const closeStreaming = async () => {
   210→    if (streamingStartPromise) {
   211→      await streamingStartPromise;
   212→    }
   213→    await partialUpdateQueue;
   214→    if (streaming?.isActive()) {
   215→      let text = streamText;
   216→      if (mentionTargets?.length) {
   217→        text = buildMentionedCardContent(mentionTargets, text);
   218→      }
   219→      await streaming.close(text);
   220→    }
   221→    streaming = null;
   222→    streamingStartPromise = null;
   223→    streamText = "";
   224→    lastPartial = "";
   225→  };
   226→
   227→  const sendChunkedTextReply = async (params: {
   228→    text: string;
   229→    useCard: boolean;
   230→    infoKind?: string;
   231→  }) => {
   232→    let first = true;
   233→    const chunkSource = params.useCard
   234→      ? params.text
   235→      : core.channel.text.convertMarkdownTables(params.text, tableMode);
   236→    for (const chunk of core.channel.text.chunkTextWithMode(
   237→      chunkSource,
   238→      textChunkLimit,
   239→      chunkMode,
   240→    )) {
   241→      const message = {
   242→        cfg,
   243→        to: chatId,
   244→        text: chunk,
   245→        replyToMessageId: sendReplyToMessageId,
   246→        replyInThread: effectiveReplyInThread,
   247→        mentions: first ? mentionTargets : undefined,
   248→        accountId,
   249→      };
   250→      if (params.useCard) {
   251→        await sendMarkdownCardFeishu(message);
   252→      } else {
   253→        await sendMessageFeishu(message);
   254→      }
   255→      first = false;
   256→    }
   257→    if (params.infoKind === "final") {
   258→      deliveredFinalTexts.add(params.text);
   259→    }
   260→  };
   261→
   262→  const { dispatcher, replyOptions, markDispatchIdle } =
   263→    core.channel.reply.createReplyDispatcherWithTyping({
   264→      responsePrefix: prefixContext.responsePrefix,
   265→      responsePrefixContextProvider: prefixContext.responsePrefixContextProvider,
   266→      humanDelay: core.channel.reply.resolveHumanDelayConfig(cfg, agentId),
   267→      onReplyStart: () => {
   268→        deliveredFinalTexts.clear();
   269→        if (streamingEnabled && renderMode === "card") {
   270→          startStreaming();
   271→        }
   272→        void typingCallbacks.onReplyStart?.();
   273→      },
   274→      deliver: async (payload: ReplyPayload, info) => {
   275→        const text = payload.text ?? "";
   276→        const mediaList =
   277→          payload.mediaUrls && payload.mediaUrls.length > 0
   278→            ? payload.mediaUrls
   279→            : payload.mediaUrl
   280→              ? [payload.mediaUrl]
   281→              : [];
   282→        const hasText = Boolean(text.trim());
   283→        const hasMedia = mediaList.length > 0;
   284→        const skipTextForDuplicateFinal =
   285→          info?.kind === "final" && hasText && deliveredFinalTexts.has(text);
   286→        const shouldDeliverText = hasText && !skipTextForDuplicateFinal;
   287→
   288→        if (!shouldDeliverText && !hasMedia) {
   289→          return;
   290→        }
   291→
   292→        if (shouldDeliverText) {
   293→          const useCard = renderMode === "card" || (renderMode === "auto" && shouldUseCard(text));
   294→
   295→          if (info?.kind === "block") {
   296→            // Drop internal block chunks unless we can safely consume them as
   297→            // streaming-card fallback content.
   298→            if (!(streamingEnabled && useCard)) {
   299→              return;
   300→            }
   301→            startStreaming();
   302→            if (streamingStartPromise) {
   303→              await streamingStartPromise;
   304→            }
   305→          }
   306→
   307→          if (info?.kind === "final" && streamingEnabled && useCard) {
   308→            startStreaming();
   309→            if (streamingStartPromise) {
   310→              await streamingStartPromise;
   311→            }
   312→          }
   313→
   314→          if (streaming?.isActive()) {
   315→            if (info?.kind === "block") {
   316→              // Some runtimes emit block payloads without onPartial/final callbacks.
   317→              // Mirror block text into streamText so onIdle close still sends content.
   318→              queueStreamingUpdate(text, { mode: "delta" });
   319→            }
   320→            if (info?.kind === "final") {
   321→              streamText = mergeStreamingText(streamText, text);
   322→              await closeStreaming();
   323→              deliveredFinalTexts.add(text);
   324→            }
   325→            // Send media even when streaming handled the text
   326→            if (hasMedia) {
   327→              for (const mediaUrl of mediaList) {
   328→                await sendMediaFeishu({
   329→                  cfg,
   330→                  to: chatId,
   331→                  mediaUrl,
   332→                  replyToMessageId: sendReplyToMessageId,
   333→                  replyInThread: effectiveReplyInThread,
   334→                  accountId,
   335→                });
   336→              }
   337→            }
   338→            return;
   339→          }
   340→
   341→          if (useCard) {
   342→            await sendChunkedTextReply({ text, useCard: true, infoKind: info?.kind });
   343→          } else {
   344→            await sendChunkedTextReply({ text, useCard: false, infoKind: info?.kind });
   345→          }
   346→        }
   347→
   348→        if (hasMedia) {
   349→          for (const mediaUrl of mediaList) {
   350→            await sendMediaFeishu({
   351→              cfg,
   352→              to: chatId,
   353→              mediaUrl,
   354→              replyToMessageId: sendReplyToMessageId,
   355→              replyInThread: effectiveReplyInThread,
   356→              accountId,
   357→            });
   358→          }
   359→        }
   360→      },
   361→      onError: async (error, info) => {
   362→        params.runtime.error?.(
   363→          `feishu[${account.accountId}] ${info.kind} reply failed: ${String(error)}`,
   364→        );
   365→        await closeStreaming();
   366→        typingCallbacks.onIdle?.();
   367→      },
   368→      onIdle: async () => {
   369→        await closeStreaming();
   370→        typingCallbacks.onIdle?.();
   371→      },
   372→      onCleanup: () => {
   373→        typingCallbacks.onCleanup?.();
   374→      },
   375→    });
   376→
   377→  return {
   378→    dispatcher,
   379→    replyOptions: {
   380→      ...replyOptions,
   381→      onModelSelected: prefixContext.onModelSelected,
   382→      disableBlockStreaming: true,
   383→      onPartialReply: streamingEnabled
   384→        ? (payload: ReplyPayload) => {
   385→            if (!payload.text) {
   386→              return;
   387→            }
   388→            queueStreamingUpdate(payload.text, {
   389→              dedupeWithLastPartial: true,
   390→              mode: "snapshot",
   391→            });
   392→          }
   393→        : undefined,
   394→    },
   395→    markDispatchIdle,
   396→  };
   397→}
