   154→  const candidate = parsed as { elements?: unknown };
   155→  if (!Array.isArray(candidate.elements)) {
   156→    return "[Interactive Card]";
   157→  }
   158→
   159→  const texts: string[] = [];
   160→  for (const element of candidate.elements) {
   161→    if (!element || typeof element !== "object") {
   162→      continue;
   163→    }
   164→    const item = element as {
   165→      tag?: string;
   166→      content?: string;
   167→      text?: { content?: string };
